<?php namespace App\Services\Auth; use App\Models\User; use App\Models\Auth\LoginSession; use Illuminate\Support\Facades\Hash; class AuthService { public function __construct(private TokenService $tokenService) {} public function login($email, $password, $lat, $long, $fingerprint, $userAgent) { $user = User::where('email', $email)->firstOrFail(); if (!Hash::check($password, $user->password_hash)) throw new \Exception('Invalid credentials'); if (!$lat || !$long) throw new \Exception('Location required'); LoginSession::create(['user_id' => $user->id, 'device_fingerprint' => $fingerprint, 'device_os' => $this->parseOS($userAgent), 'device_browser' => $this->parseBrowser($userAgent), 'ip_address' => request()->ip(), 'latitude' => $lat, 'longitude' => $long]); $tokens = $this->tokenService->generateTokenPair($user); return ['user' => $user->only('id', 'email', 'first_name', 'last_name'), 'tokens' => $tokens]; } private function parseOS($ua) { preg_match('/Windows|Mac|Linux|Android|iOS/', $ua, $m); return $m[0] ?? 'Unknown'; } private function parseBrowser($ua) { preg_match('/Chrome|Firefox|Safari|Edge/', $ua, $m); return $m[0] ?? 'Unknown'; } }
